import sqlite3
import threading
from contextlib import contextmanager

# Simulated database connection
class DatabaseConnection:
    def __init__(self):
        self.conn = sqlite3.connect(':memory:', check_same_thread=False)
        self.conn.execute('''CREATE TABLE IF NOT EXISTS permissions
                           (user_id INTEGER, file_id INTEGER, access_level TEXT)''')
        self.conn.execute('''CREATE TABLE IF NOT EXISTS files
                           (file_id INTEGER, content TEXT)''')
        self.conn.commit()
        
    def execute_query(self, query, params=None):
        cursor = self.conn.cursor()
        if params:
            cursor.execute(query, params)
        else:
            cursor.execute(query)
        return cursor.fetchall()
    
    def execute_update(self, query, params=None):
        cursor = self.conn.cursor()
        if params:
            cursor.execute(query, params)
        else:
            cursor.execute(query)
        self.conn.commit()
        return cursor.rowcount

# Global database instance
db = DatabaseConnection()

# Thread-safe file access control system
class FileAccessControl:
    def __init__(self):
        self.lock = threading.RLock()
    
    @contextmanager
    def get_db_connection(self):
        """Thread-safe database connection context manager"""
        try:
            yield db
        except Exception:
            db.conn.rollback()
            raise
    
    def check_user_permission(self, user_id, file_id):
        """Check if user has permission to access file"""
        with self.get_db_connection() as database:
            result = database.execute_query(
                "SELECT access_level FROM permissions WHERE user_id = ? AND file_id = ?",
                (user_id, file_id)
            )
            return result[0][0] if result else None
    
    def get_file_content(self, user_id, file_id):
        """Securely check permission and return file content"""
        with self.lock:
            # Check permission first
            access_level = self.check_user_permission(user_id, file_id)
            
            # Validate permission
            if not access_level or access_level not in ['read', 'write', 'admin']:
                raise PermissionError(f"User {user_id} does not have read permission for file {file_id}")
            
            # Get file content
            with self.get_db_connection() as database:
                result = database.execute_query(
                    "SELECT content FROM files WHERE file_id = ?",
                    (file_id,)
                )
                if not result:
                    raise FileNotFoundError(f"File {file_id} not found")
                return result[0][0]

# Secure implementation with proper transaction handling
class SecureFileAccessControl:
    def __init__(self):
        self.lock = threading.RLock()
    
    @contextmanager
    def transaction(self):
        """Ensure atomic operations"""
        try:
            yield db
        except Exception as e:
            db.conn.rollback()
            raise e
    
    def check_and_get_file(self, user_id, file_id):
        """Thread-safe check and get file operation"""
        with self.lock:
            # Single atomic operation to check permission and get content
            with self.transaction() as database:
                # Check permission
                permission_result = database.execute_query(
                    "SELECT access_level FROM permissions WHERE user_id = ? AND file_id = ?",
                    (user_id, file_id)
                )
                
                if not permission_result:
                    raise PermissionError(f"User {user_id} has no access to file {file_id}")
                
                access_level = permission_result[0][0]
                if access_level not in ['read', 'write', 'admin']:
                    raise PermissionError(f"User {user_id} lacks read permission for file {file_id}")
                
                # Get file content in same transaction
                content_result = database.execute_query(
                    "SELECT content FROM files WHERE file_id = ?",
                    (file_id,)
                )
                
                if not content_result:
                    raise FileNotFoundError(f"File {file_id} not found")
                
                return content_result[0][0]

